from instructor import from_openai
from instructor.retry import with_exponential_backoff
from vex import verify

client = from_openai(OpenAI(), mode=with_exponential_backoff())

class Policy(BaseModel):
    window_days: int
    conditions: List[str]
    accessibility: Dict[str, bool]  # ADA compliance

@verify(max_retries=3)
def extract_policy(product_desc: str) -> Policy:
    return client.chat.completions.create(
        model='gpt-4o',
        response_model=Policy,
        messages=[{'role': 'user', 'content': product_desc}]
    )

policy = extract_policy('30-day returns if tags attached, screen reader compatible');
